"""Tests for agentpulse.client.config."""

import json
from pathlib import Path

from agentpulse.client.config import ClientConfig, load_client_config


class TestLoadClientConfig:
    def test_missing_file_returns_none(self, tmp_path: Path) -> None:
        assert load_client_config(tmp_path / "missing.json") is None

    def test_malformed_json_returns_none(self, tmp_path: Path) -> None:
        config = tmp_path / "c.json"
        config.write_text("{not json")
        assert load_client_config(config) is None

    def test_missing_host_returns_none(self, tmp_path: Path) -> None:
        config = tmp_path / "c.json"
        config.write_text(json.dumps({"port": 17385}))
        assert load_client_config(config) is None

    def test_missing_port_returns_none(self, tmp_path: Path) -> None:
        config = tmp_path / "c.json"
        config.write_text(json.dumps({"host": "127.0.0.1"}))
        assert load_client_config(config) is None

    def test_minimal_valid_config(self, tmp_path: Path) -> None:
        config = tmp_path / "c.json"
        config.write_text(json.dumps({"host": "127.0.0.1", "port": 17385}))
        loaded = load_client_config(config)
        assert loaded == ClientConfig(host="127.0.0.1", port=17385)

    def test_fetch_limits_default_true(self, tmp_path: Path) -> None:
        config = tmp_path / "c.json"
        config.write_text(json.dumps({"host": "127.0.0.1", "port": 17385}))
        loaded = load_client_config(config)
        assert loaded is not None
        assert loaded.fetch_limits is True

    def test_fetch_limits_false_honored(self, tmp_path: Path) -> None:
        config = tmp_path / "c.json"
        config.write_text(
            json.dumps({"host": "127.0.0.1", "port": 17385, "fetch_limits": False})
        )
        loaded = load_client_config(config)
        assert loaded is not None
        assert loaded.fetch_limits is False

    def test_extra_keys_are_ignored(self, tmp_path: Path) -> None:
        """The client only reads its own keys; server keys must not break it."""
        config = tmp_path / "c.json"
        config.write_text(
            json.dumps(
                {
                    "host": "127.0.0.1",
                    "port": 17385,
                    "db_path": "/some/path.db",
                    "log_level": "DEBUG",
                }
            )
        )
        loaded = load_client_config(config)
        assert loaded is not None
        assert loaded.host == "127.0.0.1"
